      <li>\u300C\u4E2D\u7D99\u30B5\u30FC\u30D0\u306B\u63A5\u7D9A\u3067\u304D\u307E\u305B\u3093\u300D\u304C\u51FA\u305F\u3089\u3001relay\uFF08\u5225\u30A6\u30A3\u30F3\u30C9\u30A6\uFF09\u304C\u8D77\u52D5\u3057\u3066\u3044\u308B\u304B\u78BA\u8A8D\u3057\u300C\u518D\u63A5\u7D9A\u300D\u3092\u62BC\u3057\u307E\u3059\u3002</li>
